def normalize_resource_name(name):
    text = (name or '').strip()
    text = re.sub(r'\s*[\uFF08(][^\uFF09)]*[\uFF09)]\s*$', '', text).strip()
    text = re.sub(r'\s+', ' ', text)
    return text.casefold()


def get_resource_description(module, name):
    module_map = RESOURCE_DESCRIPTIONS.get(module, {})
    if name in module_map:
        return module_map[name]

    normalized = normalize_resource_name(name)
    for source_name, description in module_map.items():
        if normalize_resource_name(source_name) == normalized:
            return description
    return None
